import clsx from 'clsx';

import { ChevronDownSmallIcon, ContainerIcon } from '@dynatrace/strato-icons';

import * as styles from './SegmentSelectorTrigger.sty.js';
import { Button } from '../../../../buttons/button/Button.js';
import { AriaLabelingProps } from '../../../../core/types/a11y-props.js';
import { DataTestId } from '../../../../core/types/data-props.js';
import { StylingProps } from '../../../../core/types/styling-props.js';
import { mergeProps as _mergeProps } from '../../../../core/utils/merge-props.js';
import { TextEllipsis } from '../../../../typography/text-ellipsis/TextEllipsis.js';
import { useSegmentsTriggerContext } from '../../hooks/useTriggerContext.js';

type SegmentSelectorTriggerProps = AriaLabelingProps &
  DataTestId &
  StylingProps & {
    textEllipsisRef: (ref: HTMLSpanElement | null) => void;
  };

/**
 * The default Trigger for the SegmentSelector.
 * @internal
 */
export const SegmentSelectorTrigger = (props: SegmentSelectorTriggerProps) => {
  const {
    textEllipsisRef,
    className: consumerClassName,
    ...remainingProps
  } = props;

  const { triggerProps, displayValue, isLoading, buttonRef, showError } =
    useSegmentsTriggerContext();

  return (
    <Button
      ref={buttonRef}
      loading={isLoading}
      variant="emphasized"
      textAlign="start"
      color={showError ? 'critical' : 'neutral'}
      className={clsx(styles.trigger, consumerClassName)}
      {..._mergeProps(triggerProps, remainingProps)}
    >
      <Button.Prefix>
        <ContainerIcon />
      </Button.Prefix>
      {displayValue && (
        <TextEllipsis ref={textEllipsisRef}>{displayValue}</TextEllipsis>
      )}
      <Button.Suffix>
        <ChevronDownSmallIcon />
      </Button.Suffix>
    </Button>
  );
};

(
  SegmentSelectorTrigger as typeof SegmentSelectorTrigger & {
    displayName: string;
  }
).displayName = 'SegmentSelectorTrigger';
